steps.script:
const requestedHandle = '{handle}'.replace(/^@+/, '').trim().toLowerCase();
const targetCount = Math.max(1, Math.min(500, Number('{target_count}') || 36));
const maxScrolls = Math.max(0, Math.min(160, Number('{max_scrolls}') || 8));
const maxIdleScrolls = Math.max(1, Math.min(12, Number('{max_idle_scrolls}') || 3));
const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
const normalizeText = (value) => (value || '').replace(/\s+/g, ' ').trim();
const normalizeUrl = (raw) => {
  if (!raw) return '';
  try {
    return new URL(raw, window.location.origin).toString();
  } catch {
    return String(raw);
  }
};
const parsePostRef = (raw) => {
  const absolute = normalizeUrl(raw);
  if (!absolute) return null;
  let parsed;
  try {
    parsed = new URL(absolute);
  } catch {
    return null;
  }
  const parts = parsed.pathname.split('/').filter(Boolean);
  const kindIndex = parts.findIndex((part) => /^(p|reel|tv)$/i.test(part));
  if (kindIndex < 0 || kindIndex + 1 >= parts.length) return null;
  const kind = parts[kindIndex].toLowerCase();
  const shortcode = parts[kindIndex + 1];
  const ownerHandle = kindIndex > 0 ? parts[kindIndex - 1].replace(/^@+/, '').toLowerCase() : '';
  return {
    absolute,
    canonical_url: parsed.origin + '/' + kind + '/' + shortcode + '/',
    kind,
    shortcode,
    owner_handle: ownerHandle
  };
};
const visibleText = (node) => normalizeText(node?.innerText || node?.textContent || node?.getAttribute?.('aria-label') || '');
const hasMediaLinks = () => Array.from(document.querySelectorAll("main a[href]")).some((anchor) => {
  const ref = parsePostRef(anchor.getAttribute('href') || anchor.href || '');
  if (!ref) return false;
  return !requestedHandle || !ref.owner_handle || ref.owner_handle === requestedHandle;
});
const waitForMediaLinks = async () => {
  const deadline = Date.now() + 6000;
  while (Date.now() < deadline) {
    if (hasMediaLinks()) return true;
    await sleep(350);
  }
  return hasMediaLinks();
};
const candidates = new Map();
const collect = () => {
  for (const anchor of Array.from(document.querySelectorAll("main a[href]"))) {
    const ref = parsePostRef(anchor.getAttribute('href') || anchor.href || '');
    if (!ref) continue;
    if (requestedHandle && ref.owner_handle && ref.owner_handle !== requestedHandle) continue;
    if (candidates.has(ref.canonical_url)) continue;
    const thumbnail = anchor.querySelector('img');
    const indicatorText = Array.from(anchor.querySelectorAll('svg[aria-label], [aria-label], span')).map(visibleText).filter(Boolean).join(' | ');
    const entry = {
      post_url: ref.canonical_url,
      shortcode: ref.shortcode,
      kind_hint: ref.kind,
      thumbnail_url: normalizeUrl(thumbnail?.currentSrc || thumbnail?.getAttribute?.('src') || ''),
      alt_text: normalizeText(thumbnail?.getAttribute?.('alt') || ''),
      indicator_text: indicatorText || null
    };
    candidates.set(ref.canonical_url, entry);
  }
  return candidates.size;
};
window.scrollTo(0, 0);
await sleep(350);
const linksReady = await waitForMediaLinks();
let idleScrolls = 0;
let lastCount = collect();
let executedScrolls = 0;
for (let pass = 0; pass < maxScrolls; pass += 1) {
  if (candidates.size >= targetCount) break;
  const beforeY = window.scrollY;
  const beforeHeight = Math.max(document.body?.scrollHeight || 0, document.documentElement?.scrollHeight || 0);
  window.scrollBy(0, Math.max(window.innerHeight * 1.1, 960));
  executedScrolls += 1;
  await sleep(950);
  const currentCount = collect();
  const afterY = window.scrollY;
  const afterHeight = Math.max(document.body?.scrollHeight || 0, document.documentElement?.scrollHeight || 0);
  const countGrew = currentCount > lastCount;
  const pageAdvanced = Math.abs(afterY - beforeY) >= 16 || afterHeight > beforeHeight;
  if (countGrew || pageAdvanced) idleScrolls = 0;
  else idleScrolls += 1;
  lastCount = currentCount;
  if (idleScrolls >= maxIdleScrolls) break;
}
collect();
const candidateList = Array.from(candidates.values()).slice(0, targetCount);
return {
  profile_url: normalizeUrl(window.location.href),
  profile_title: document.title,
  handle: requestedHandle || normalizeText(location.pathname.split('/').filter(Boolean)[0] || ''),
  links_ready: linksReady,
  total_candidates: candidateList.length,
  scroll_passes: executedScrolls,
  idle_scroll_termination: idleScrolls >= maxIdleScrolls,
  candidates: candidateList
};
